import{C as t,o as n,c as o,a5 as a,E as l}from"./chunks/framework.CW28V7p_.js";const c=JSON.parse('{"title":"4. Alpenglow (SIMD-0326) overview","description":"","frontmatter":{},"headers":[],"relativePath":"module-4/4-alpenglow.md","filePath":"module-4/4-alpenglow.md","lastUpdated":1780937944000}'),r={name:"module-4/4-alpenglow.md"},g=Object.assign(r,{setup(p){const e={id:"m4-4-alpenglow",title:"🧠 Mini-check: Alpenglow",intro:"3 питання — твоя priority topic. Концепти що ти оперуєш кожен день на WNX0016778.",questions:[{type:"compare",q:"У чому ключові різниці між Tower BFT (current mainnet) і Alpenglow (SIMD-0326)?",ideal:`1. Voting mechanism: Tower BFT use individual vote TXs per slot. Alpenglow uses BLS aggregated signatures — кілька validators sign single combined message, reduces network overhead.

2. Credits semantics: Tower BFT credits = 1 per successful vote (count of votes). Alpenglow epochCredits = lamport reward earned (актуальний рублевий результат, not vote count). Це fundamentally different — Alpenglow "accuracy metric" must normalize by stake to compare validators fairly.

3. Finality speed: Tower BFT ~12-30 sec (depth 32 у tower). Alpenglow targets faster finality через improved voting protocol.

4. Network efficiency: BLS aggregation reduces vote TX volume по cluster significantly — менше bandwidth для same security.

5. Slashing: Alpenglow proposed більш строгий slashing для double-signs і protocol violations.

6. Current status: Tower BFT live mainnet. Alpenglow community cluster (твій WNX0016778), не mainnet ще.`,explanation:"Ключове: BLS aggregation, lamport-based credits, faster finality, stricter slashing. Module 4.4."},{type:"diagnose",q:'Твій Telegram bot на Alpenglow showed "Credits: ?" у Final Reports. Worked правильно для slot lag, але не для credits. Що могло бути cause і як це relates до SIMD-0326 semantics?',options:["Bot script парсив credits як integer count (Tower BFT style), але Alpenglow повертає lamport amount — parsing failed","RPC endpoint не повертав credits field у response",'Bash echo "$json" | python3 <<EOF pipe+heredoc concatenation issue (technical bug)',"Validator stopped voting"],correct:[0,2],explanation:"Real cause був technical bash bug (pipe+heredoc concatenation, fixed by switch to python3 -c). АЛЕ також conceptual issue: на Alpenglow credits != vote count, тому naive parsing/comparison may fail. Validator був voting, RPC returned data. Module 4.4."},{type:"mcq",q:"Що з цього потрібно для validator on Alpenglow community cluster (vs mainnet)?",options:["BLS pubkey (auto-set via V2 create-vote-account instruction)","VAT (Validator Admission Ticket) — 1.6 SOL/epoch","Stake minimum 1 SOL для voting","KYC verification through Anza"],correct:[0,1,2],explanation:"#1 BLS pubkey — Alpenglow consensus aggregation key. #2 VAT — admission mechanism (з cheatsheet §15). #3 1 SOL minimum self-stake. #4 KYC не потрібен — community cluster permissionless. Module 4.4."}]};return(h,s)=>{const i=t("Quiz");return n(),o("div",null,[s[0]||(s[0]=a("",67)),l(i,{data:e}),s[1]||(s[1]=a("",6))])}}});export{c as __pageData,g as default};
